#include<bits/stdc++.h>
using namespace std;
long long dp[1000010];
const long long mod=998244353;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
long long a[1000010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    long long ans=0,ny=fastpow(n,mod-2);
    dp[0]=1;
    for(int i=1;i<=n;i++)
    {
        dp[i]=dp[i-1]*ny%mod;
        ans+=dp[i]*a[i]%mod;
        dp[i]+=dp[i-1];
        dp[i]%=mod;
        ans%=mod;
    }
    printf("%lld",ans);
    return 0;
}
